import type FeatureFilter from "../../layers/support/FeatureFilter.js";
import type SizeVariable from "../../renderers/visualVariables/SizeVariable.js";
import type MapView from "../../views/MapView.js";
import type { MapViewOrSceneView } from "../../views/MapViewOrSceneView.js";
import type { AbortOptions } from "../../core/promiseUtils.js";
import type { SupportedLayer } from "../types.js";

/**
 * Suggested `min` and `max` scales to apply to the input layer for the [scaleRange()](https://developers.arcgis.com/javascript/latest/references/core/smartMapping/heuristics/scaleRange/#scaleRange)
 * function.
 *
 * @since 5.0
 */
export interface ScaleRangeResult {
  /**
   * The suggested [FeatureLayer.minScale](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#minScale)
   *   to apply to the input layer.
   *
   * @since 5.0
   */
  minScale: number;
  /**
   * The suggested [FeatureLayer.maxScale](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#maxScale)
   *   to apply to the input layer.
   *
   * @since 5.0
   */
  maxScale: number;
}

/**
 * The suggested `minSize` and `maxSize` size variables generated from the [sizeRange()](https://developers.arcgis.com/javascript/latest/references/core/smartMapping/heuristics/sizeRange/#sizeRange)
 * function to apply to the
 * [SizeVariable](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/SizeVariable/) used for scale-dependent bounded proportional symbols.
 *
 * @since 5.0
 */
export interface SizeRangeResult {
  /**
   * The suggested sizes of the smallest symbols at various scales in a layer with a
   *   [size visualization](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/SizeVariable/).
   *   Note that this must be a *scale-dependent stops* size variable according to the Size Variable documentation.
   *
   * @since 5.0
   */
  minSize: SizeVariable;
  /**
   * The suggested sizes of the largest symbols at various scales in a layer with a
   *   [size visualization](https://developers.arcgis.com/javascript/latest/references/core/renderers/visualVariables/SizeVariable/).
   *   Note that this must be a *scale-dependent stops* size variable according to the Size Variable documentation.
   *
   * @since 5.0
   */
  maxSize: SizeVariable;
}

/** @since 5.0 */
export interface ScaleRangeParameters extends AbortOptions {
  /**
   * The layer for which to generate a suggested min/max scale range.
   *
   * @since 5.0
   */
  layer: SupportedLayer;
  /**
   * The [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/) or [MapView](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/)
   *   where the layer will be rendered. This property is required when generating a scale range for any layer that is not tiled.
   *
   * @since 5.0
   */
  view?: MapViewOrSceneView | null;
  /**
   * When defined, only features included in the filter
   *   are considered in the attribute and spatial statistics calculations when determining the final renderer.
   *   This is useful when a lot of variation exists in the data
   *   that could result in undesired data ranges. A common use case would be to set a filter that only
   *   includes features in the current extent of the view where the data is most likely to be viewed. Currently, only
   *   geometry filters with an `intersects` spatial relationship are supported. All other filter types (including `where`) are ignored.
   *
   * @since 5.0
   */
  filter?: FeatureFilter | null;
  /**
   * The number of features in the `layer` to sample for spatial
   *   statistics. A higher sample size will yield more precise results. However, higher sample sizes also
   *   require more time for the function to process the result.
   *
   * @default 500
   * @since 5.0
   */
  sampleSize?: number | null;
  /**
   * Indicates whether the generated renderer is for a binning visualization.
   *
   * @since 5.0
   */
  forBinning?: boolean | null;
}

/** @since 5.0 */
export interface SizeRangeParameters extends AbortOptions {
  /**
   * The layer for which to generate a suggested min/max size range based on scale for a size visual variable.
   *
   * @since 5.0
   */
  layer: SupportedLayer;
  /**
   * The [MapView](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/)
   *   or [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/) where the layer will be rendered.
   *
   * @since 5.0
   */
  view?: MapViewOrSceneView | null;
  /**
   * When defined, only features included in the filter
   *   are considered in the attribute and spatial statistics calculations when determining the final renderer.
   *   This is useful when a lot of variation exists in the data
   *   that could result in undesired data ranges. A common use case would be to set a filter that only
   *   includes features in the current extent of the view where the data is most likely to be viewed. Currently, only
   *   geometry filters with an `intersects` spatial relationship are supported. All other filter types (including `where`) are ignored.
   *
   * @since 5.0
   */
  filter?: FeatureFilter | null;
  /**
   * Indicates whether the generated renderer is for a binning visualization.
   *
   * @since 5.0
   */
  forBinning?: boolean | null;
}

/** @since 5.0 */
export interface BinLevelParameters {
  /**
   * The [MapView](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/)
   *   where the layer will be rendered.
   *
   * @since 5.0
   */
  view: MapView;
}